import { describe, it, expect } from 'vitest';
import request from 'supertest';
import { sign, HOOK_SIGNATURE_HEADER } from '@orchestkit/hook-contract/signing';
import { createApp } from '../server.js';

// 64 hex chars = 32 bytes — above the weak-secret advisory floor.
const SECRET = 'a'.repeat(64);
const app = createApp(SECRET);

/**
 * Sign the exact bytes and POST them, matching the raw-body HMAC contract.
 * Uses application/octet-stream so supertest transmits the Buffer verbatim —
 * under application/json superagent re-serializes it and breaks the signature.
 * The sink captures any content type and only cares about the raw bytes.
 */
function post(body: Buffer, header?: string) {
  const req = request(app).post('/hooks/ingest').set('Content-Type', 'application/octet-stream');
  if (header !== undefined) req.set(HOOK_SIGNATURE_HEADER, header);
  return req.send(body);
}

describe('generic hook-sink server', () => {
  it('accepts a validly signed known event with 202', async () => {
    const body = Buffer.from(
      JSON.stringify({ event: 'PreToolUse', session_id: 'demo', payload: { tool_name: 'Bash' } }),
    );
    const res = await post(body, sign(body, SECRET));

    expect(res.status).toBe(202);
    expect(res.body).toEqual({ ok: true, event: 'PreToolUse' });
  });

  it('rejects a tampered signature with 401 signature_mismatch', async () => {
    const body = Buffer.from(JSON.stringify({ event: 'PreToolUse', payload: { tool_name: 'Bash' } }));
    // Flip the last hex nibble of the v1 digest so the HMAC no longer matches.
    const header = sign(body, SECRET);
    const tampered = header.slice(0, -1) + (header.endsWith('0') ? '1' : '0');
    const res = await post(body, tampered);

    expect(res.status).toBe(401);
    expect(res.body).toEqual({ ok: false, reason: 'signature_mismatch' });
  });

  it('rejects an absent signature with 400 missing_header', async () => {
    const body = Buffer.from(JSON.stringify({ event: 'PreToolUse' }));
    const res = await post(body); // no header

    expect(res.status).toBe(400);
    expect(res.body).toEqual({ ok: false, reason: 'missing_header' });
  });

  it('rejects a stale timestamp with 401 stale', async () => {
    const body = Buffer.from(JSON.stringify({ event: 'PreToolUse' }));
    // Sign 10000s in the past — well outside the default 300s replay tolerance.
    const staleTs = Math.floor(Date.now() / 1000) - 10_000;
    const res = await post(body, sign(body, SECRET, { timestamp: staleTs }));

    expect(res.status).toBe(401);
    expect(res.body).toEqual({ ok: false, reason: 'stale' });
  });

  it('rejects a valid signature over non-JSON bytes with 400 invalid_json', async () => {
    const body = Buffer.from('not json at all {{{');
    const res = await post(body, sign(body, SECRET));

    expect(res.status).toBe(400);
    expect(res.body).toEqual({ ok: false, reason: 'invalid_json' });
  });
});
